examples.question:
Find $\tan G$ in the right triangle shown below.

[asy]

pair H,F,G;

H = (0,0);

G = (15,0);

F = (0,8);

draw(F--G--H--F);

draw(rightanglemark(F,H,G,20));

label("$H$",H,SW);

label("$G$",G,SE);

label("$F$",F,N);

label("$17$",(F+G)/2,NE);

label("$15$",G/2,S);

[/asy]

The circumference of a circle $A$ is 60 feet. How many feet long is $\widehat{BC}$? [asy]
import markers;

import olympiad; import geometry; import graph; size(150); defaultpen(linewidth(0.9));
draw(Circle(origin,1));
draw(dir(90)--origin--dir(30));
label("$B$",dir(90),N);
label("$A$",origin,S);
label("$C$",dir(30),E);
markangle(Label("$60^{\circ}$"),dir(30),origin,(0,1),radius=20);
[/asy]

